package com.google.gson.examples.android.model;
import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.lang.reflect.WildcardType;
import com.google.gson.annotations.SerializedName;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.util.Collections;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CartTest {

  private Object cart;
  private String buyerName = "John Doe";

  @BeforeEach
  void setUp() throws Exception {
    List<?> lineItems = Collections.emptyList();
    String creditCard = "1234-5678-9012-3456";

    Class<?> cartClass = Class.forName("com.google.gson.examples.android.model.Cart");
    cart = cartClass.getConstructor(List.class, String.class, String.class)
        .newInstance(lineItems, buyerName, creditCard);
  }

  @Test
  void testGetBuyerName() throws Exception {
    Class<?> cartClass = cart.getClass();
    String actualBuyerName = (String) cartClass.getMethod("getBuyerName").invoke(cart);
    assertEquals(buyerName, actualBuyerName);
  }
}
